const filterAdvanced = "AREA[InterventionType](GENETIC OR BIOLOGICAL) AND AREA[StudyType]INTERVENTIONAL AND AREA[Phase](PHASE1 OR PHASE2 OR PHASE3 OR EARLY_PHASE1)";
const queries = [
  'AAV',
  '"adeno-associated"',
  'Dependovirus',
  '(AAV1 OR AAV2 OR AAV3 OR AAV4 OR AAV5 OR AAV6 OR AAV7 OR AAV8 OR AAV9 OR AAVrh10 OR rAAV)',
  '("gene therapy" AND vector)',
];
return queries.map((queryTerm, i) => ({ json: { queryTerm, filterAdvanced, queryIndex: i } }));

// Aggregate studies from all 5 queries + all pagination pages; deduplicate by NCT ID.
const allItems = $input.all();
const seen = new Set();
const uniqueStudies = [];
let totalBeforeDedup = 0;

for (const item of allItems) {
  const studies = item.json.studies || [];
  totalBeforeDedup += studies.length;
  for (const study of studies) {
    const nct = study.protocolSection && study.protocolSection.identificationModule
      ? study.protocolSection.identificationModule.nctId : null;
    if (nct && !seen.has(nct)) {
      seen.add(nct);
      uniqueStudies.push(study);
    }
  }
}

console.log(`Dedup: ${totalBeforeDedup} total → ${uniqueStudies.length} unique NCTs`);
// Return as single item; Extract Industry Sponsors iterates item.json.studies
return [{ json: { studies: uniqueStudies, totalBeforeDedup, totalAfterDedup: uniqueStudies.length } }];

// L1 PURE CAPTURE — extended to pass through disambiguation fields for classifier.
const items = $input.all();
const sponsors = {};
let totalStudiesProcessed = 0;
const ACTIVE = ['RECRUITING', 'ACTIVE_NOT_RECRUITING', 'ENROLLING_BY_INVITATION'];

function normDate(raw) {
  if (!raw) return null;
  if (raw.length === 4) return raw + '-01-01';
  if (raw.length === 7) return raw + '-01';
  return raw;
}

for (const item of items) {
  const studies = item.json.studies || [];
  totalStudiesProcessed += studies.length;
  for (const study of studies) {
    const proto = study.protocolSection;
    const derivedSection = study.derivedSection;
    if (!proto) continue;
    const sponsorModule = proto.sponsorCollaboratorsModule;
    const designModule = proto.designModule;
    const conditionsModule = proto.conditionsModule;
    const idModule = proto.identificationModule;
    const interventionsModule = proto.armsInterventionsModule;
    const statusModule = proto.statusModule;
    const descriptionModule = proto.descriptionModule;
    if (!sponsorModule || !sponsorModule.leadSponsor) continue;
    const leadSponsor = sponsorModule.leadSponsor;
    if (leadSponsor.class !== 'INDUSTRY') continue;

    const interventions = (interventionsModule && interventionsModule.interventions) || [];
    const rawName = leadSponsor.name.trim();
    const normKey = rawName
      .replace(/,?\s*(Inc\.?|LLC|Ltd\.?|Corp\.?|Co\.?|Incorporated|Limited|Corporation|Company|Plc|PLC|S\.?A\.?|AG|GmbH|B\.?V\.?)\s*$/i, '')
      .replace(/[.,]/g, '').trim().toLowerCase();
    if (!sponsors[normKey]) {
      sponsors[normKey] = { companyName: rawName, trialCount: 0, phases: [], conditions: [], nctIds: [], statuses: [], sampleIntervention: '', mostRecentTrialDate: null, activeRecruiting: false, trials: [] };
    }
    const s = sponsors[normKey];
    s.trialCount++;

    const phases = (designModule && designModule.phases) || [];
    for (const p of phases) { if (!s.phases.includes(p)) s.phases.push(p); }

    const conditions = (conditionsModule && conditionsModule.conditions) || [];
    for (const c of conditions) { if (!s.conditions.includes(c) && s.conditions.length < 10) s.conditions.push(c); }

    const nctId = idModule && idModule.nctId;
    if (nctId) s.nctIds.push(nctId);

    const status = statusModule && statusModule.overallStatus;
    if (status && !s.statuses.includes(status)) s.statuses.push(status);
    if (status && ACTIVE.includes(status)) s.activeRecruiting = true;

    const sd = statusModule && statusModule.startDateStruct && statusModule.startDateStruct.date;
    const ld = statusModule && statusModule.lastUpdatePostDateStruct && statusModule.lastUpdatePostDateStruct.date;
    for (const dRaw of [sd, ld]) {
      const d = normDate(dRaw);
      if (d && (!s.mostRecentTrialDate || d > s.mostRecentTrialDate)) s.mostRecentTrialDate = d;
    }

    if (!s.sampleIntervention && interventions.length > 0 && interventions[0].name) {
      s.sampleIntervention = interventions[0].name;
    }

    if (nctId) {
      s.trials.push({
        nct: nctId,
        overallStatus: status || null,
        startDate: normDate(sd),
        lastUpdateDate: normDate(ld),
        phase: phases.length > 0 ? phases[0] : null,
        briefTitle: idModule && idModule.briefTitle ? idModule.briefTitle : null,
        conditions: conditions.slice(0, 5),
        conditionsList: conditions.join('\n'),
        interventionTypes: interventions.map(i => i.type).filter(Boolean).join(', '),
        interventionNames: interventions.map(i => i.name).filter(Boolean).join('\n'),
        studyType: designModule && designModule.studyType ? designModule.studyType : null,
        primaryPurpose: designModule && designModule.designInfo ? designModule.designInfo.primaryPurpose : null,
        briefSummary: descriptionModule && descriptionModule.briefSummary ? descriptionModule.briefSummary.substring(0, 500) : null,
        meshInterventions: (derivedSection && derivedSection.interventionBrowseModule && derivedSection.interventionBrowseModule.meshes) || [],
        meshConditions: (derivedSection && derivedSection.conditionBrowseModule && derivedSection.conditionBrowseModule.meshes) || [],
        rawStudyJson: JSON.stringify(study),
      });
    }

    const collaborators = sponsorModule.collaborators || [];
    for (const collab of collaborators) {
      if (collab.class !== 'INDUSTRY') continue;
      const collabNorm = collab.name.trim()
        .replace(/,?\s*(Inc\.?|LLC|Ltd\.?|Corp\.?|Co\.?|Incorporated|Limited|Corporation|Company|Plc|PLC|S\.?A\.?|AG|GmbH|B\.?V\.?)(\s*\.)?$/i, '')
        .replace(/[.,]/g, '').trim().toLowerCase();
      if (!sponsors[collabNorm]) {
        sponsors[collabNorm] = { companyName: collab.name.trim(), trialCount: 0, phases: [], conditions: [], nctIds: [], statuses: [], sampleIntervention: '', mostRecentTrialDate: null, activeRecruiting: false, trials: [] };
      }
      const cs = sponsors[collabNorm];
      cs.trialCount++;
      for (const p of phases) { if (!cs.phases.includes(p)) cs.phases.push(p); }
      if (status && ACTIVE.includes(status)) cs.activeRecruiting = true;
      for (const dRaw of [sd, ld]) {
        const d = normDate(dRaw);
        if (d && (!cs.mostRecentTrialDate || d > cs.mostRecentTrialDate)) cs.mostRecentTrialDate = d;
      }
      if (nctId) {
        cs.trials.push({
          nct: nctId,
          overallStatus: status || null,
          startDate: normDate(sd),
          lastUpdateDate: normDate(ld),
          phase: phases.length > 0 ? phases[0] : null,
          briefTitle: idModule && idModule.briefTitle ? idModule.briefTitle : null,
          conditions: conditions.slice(0, 5),
          conditionsList: conditions.join('\n'),
          interventionTypes: interventions.map(i => i.type).filter(Boolean).join(', '),
          interventionNames: interventions.map(i => i.name).filter(Boolean).join('\n'),
          studyType: designModule && designModule.studyType ? designModule.studyType : null,
          primaryPurpose: designModule && designModule.designInfo ? designModule.designInfo.primaryPurpose : null,
          briefSummary: descriptionModule && descriptionModule.briefSummary ? descriptionModule.briefSummary.substring(0, 500) : null,
          meshInterventions: (derivedSection && derivedSection.interventionBrowseModule && derivedSection.interventionBrowseModule.meshes) || [],
          meshConditions: (derivedSection && derivedSection.conditionBrowseModule && derivedSection.conditionBrowseModule.meshes) || [],
          rawStudyJson: JSON.stringify(study),
        });
      }
    }
  }
}

const phaseRank = { 'EARLY_PHASE1': 1, 'PHASE1': 2, 'PHASE2': 3, 'PHASE3': 4 };
const phaseLabel = { 1: 'Phase 1', 2: 'Phase 1', 3: 'Phase 2', 4: 'Phase 3' };
const today = new Date().toISOString().split('T')[0];

const output = [];
for (const [key, s] of Object.entries(sponsors)) {
  let maxRank = 0;
  for (const p of s.phases) { const rank = phaseRank[p] || 0; if (rank > maxRank) maxRank = rank; }
  const mostAdvancedPhase = maxRank > 0 ? phaseLabel[maxRank] : 'Preclinical';
  output.push({
    json: {
      companyName: s.companyName,
      trialCount: s.trialCount,
      mostAdvancedPhase: mostAdvancedPhase,
      leadIndication: s.conditions.length > 0 ? s.conditions[0] : '',
      allConditions: s.conditions.join('; '),
      allPhases: s.phases.join(', '),
      allStatuses: s.statuses.join(', '),
      sampleIntervention: s.sampleIntervention,
      discoveryDate: today,
      nctIds: s.nctIds.join(', '),
      source: 'clinicaltrials_gov',
      mostRecentTrialDate: s.mostRecentTrialDate,
      activeRecruiting: s.activeRecruiting,
      _totalStudiesProcessed: totalStudiesProcessed,
      trials: s.trials
    }
  });
}
return output;

// Merge new clinicaltrials_gov source with any existing Discovery Sources
const newCompanies = $('Extract Industry Sponsors').all();
const existingRecords = $('Bulk Lookup Existing Sources').all();

function normKey(name) {
  return (name || '')
    .replace(/,?\s*(Inc\.?|LLC|Ltd\.?|Corp\.?|Co\.?|Incorporated|Limited|Corporation|Company|Plc|PLC|S\.?A\.?|AG|GmbH|B\.?V\.?)(\s*\.)?$/i, '')
    .replace(/[.,]/g, '').trim().toLowerCase();
}

const existingMap = {};
for (const rec of existingRecords) {
  const rawName = (rec.json['Company Name'] || '').trim();
  const nk = normKey(rawName);
  if (nk) {
    existingMap[nk] = {
      canonicalName: rawName,
      sources: rec.json['Discovery Sources'] || [],
      confidence: rec.json['Discovery Confidence'] || 0,
      firstDiscovered: rec.json['First Discovered'] || null
    };
  }
}

const today = new Date().toISOString().split('T')[0];
const output = [];

for (const item of newCompanies) {
  const company = item.json;
  const incomingNk = normKey(company.companyName);
  const existing = existingMap[incomingNk];
  const outputCompanyName = existing ? existing.canonicalName : company.companyName;

  let mergedSources = ['clinicaltrials_gov'];
  let firstDiscovered = today;

  if (existing) {
    const prevSources = Array.isArray(existing.sources)
      ? existing.sources.map(s => typeof s === 'object' ? s.name : s)
      : [];
    mergedSources = [...new Set([...prevSources, 'clinicaltrials_gov'])];
    firstDiscovered = existing.firstDiscovered || today;
  }

  output.push({
    json: {
      companyName: outputCompanyName,
      trialCount: company.trialCount,
      mostAdvancedPhase: company.mostAdvancedPhase,
      leadIndication: company.leadIndication,
      allConditions: company.allConditions,
      nctIds: company.nctIds,
      mergedSources: mergedSources,
      mergedConfidence: mergedSources.length,
      firstDiscovered: firstDiscovered,
      lastVerified: today,
      mostRecentTrialDate: company.mostRecentTrialDate || null,
      activeRecruiting: company.activeRecruiting === true
    }
  });
}
return output;

// Build Enrichment Runs record — v2: includes multi-query metrics and classifier tier breakdown.
const upsertedItems = $('Merge Discovery Sources').all();
const extractedItems = $('Extract Industry Sponsors').all();
const totalStudies = extractedItems.length > 0 ? (extractedItems[0].json._totalStudiesProcessed || 0) : 0;
const companiesUpserted = upsertedItems.length;

let phase1 = 0, phase2 = 0, phase3 = 0, preclinical = 0;
const companies = [];
for (const item of upsertedItems) {
  const c = item.json;
  const phase = c.mostAdvancedPhase;
  if (phase === 'Phase 3') phase3++;
  else if (phase === 'Phase 2') phase2++;
  else if (phase === 'Phase 1') phase1++;
  else preclinical++;
  companies.push(c.companyName + ' | ' + (c.mostAdvancedPhase || 'Unknown') + ' | ' + (c.leadIndication || 'N/A'));
}

const today = new Date().toISOString().split('T')[0];
const report = [
  '# ClinicalTrials.gov L1 Capture Run (v2 — multi-query + evidence capture)',
  '',
  '**Date:** ' + today,
  '**Source:** clinicaltrials.gov API v2',
  '**Queries:** AAV | adeno-associated | Dependovirus | AAV serotypes | gene therapy AND vector',
  '**Essie filters:** InterventionType(GENETIC OR BIOLOGICAL), StudyType=INTERVENTIONAL, Phase 1-3',
  '**Run Type:** L1_capture',
  '**Studies processed (post-dedup):** ' + totalStudies,
  '**Unique industry sponsors:** ' + companiesUpserted,
  '',
  '## Phase distribution',
  '- Phase 3: ' + phase3,
  '- Phase 2: ' + phase2,
  '- Phase 1: ' + phase1,
  '- Preclinical: ' + preclinical,
  '',
  '## Companies',
  'Company | Phase | Lead Indication',
  '--- | --- | ---',
  ...companies
].join('\n');

return [{
  json: {
    runName: 'CT.gov L1 Capture v2 - ' + today,
    runDate: new Date().toISOString(),
    play: 'aav-gene-therapy-ellie-outreach',
    gateVersion: 'l1-capture-v2-multiquery',
    runType: 'L1_capture',
    runMode: 'incremental',
    companiesEvaluated: totalStudies,
    passedAAV: companiesUpserted,
    rerouted: 0,
    archived: 0,
    markdownReport: report,
    workflowId: '9gcmEjq1lvOY2jZS',
    executionId: $execution.id,
    recordsIn: totalStudies,
    recordsOut: companiesUpserted,
    notes: 'L1 capture v2. Multi-query union (5 queries) + Essie filters. Evidence fields captured per trial. target_classification events written for each trial. Classifier: tier1=high, tier2=medium(LLM pending), tier3=low.'
  }
}];

// Resolve company record id from Upsert Company; join with per-trial array; explode to one item per trial.
// v3: passes through disambiguation fields (studyType, primaryPurpose, meshes, etc.) for classifier.
const upsertedItems = $input.all();
const allSponsors = $('Extract Industry Sponsors').all();

function normKey(name) {
  return (name || '')
    .replace(/,?\s*(Inc\.?|LLC|Ltd\.?|Corp\.?|Co\.?|Incorporated|Limited|Corporation|Company|Plc|PLC|S\.?A\.?|AG|GmbH|B\.?V\.?)(\s*\.)?$/i, '')
    .replace(/[.,]/g, '').trim().toLowerCase();
}

const sponsorTrialsMap = {};
for (const sponsor of allSponsors) {
  const nk = normKey(sponsor.json.companyName || '');
  if (nk && Array.isArray(sponsor.json.trials)) {
    sponsorTrialsMap[nk] = sponsor.json.trials;
  }
}

const ENDED = ['TERMINATED', 'WITHDRAWN', 'SUSPENDED'];
const ACTIVE_STATUSES = ['RECRUITING', 'ACTIVE_NOT_RECRUITING', 'ENROLLING_BY_INVITATION', 'NOT_YET_RECRUITING'];
const fiveYearsMs = 5 * 365.25 * 24 * 60 * 60 * 1000;
const now = Date.now();
const runDate = new Date().toISOString().split('T')[0];

function computeVitality(overallStatus, startDate, lastUpdateDate) {
  if (!overallStatus) return 'unknown';
  const s = overallStatus.toUpperCase().trim();
  if (ENDED.includes(s)) return 'ended';
  if (ACTIVE_STATUSES.includes(s)) return 'active';
  const refDate = lastUpdateDate || startDate;
  if (!refDate) return 'dormant';
  const d = new Date(refDate);
  if (isNaN(d.getTime())) return 'unknown';
  return (now - d.getTime()) <= fiveYearsMs ? 'active' : 'dormant';
}

const output = [];
for (const item of upsertedItems) {
  const recordId = item.json.id;
  if (!recordId) continue;
  const companyName = (item.json.fields && item.json.fields['Company Name']) || '';
  const lookupKey = normKey(companyName);
  const trials = sponsorTrialsMap[lookupKey] || [];

  for (const trial of trials) {
    if (!trial.nct) continue;
    const eventDate = trial.lastUpdateDate || trial.startDate || null;
    const vitality = computeVitality(trial.overallStatus, trial.startDate, trial.lastUpdateDate);
    const phaseStr = trial.phase || '';
    const briefTitle = trial.briefTitle || '';
    const detail = [briefTitle, phaseStr].filter(Boolean).join(' | ');
    const eventId = companyName + ' — clinical_trial_status — ' + trial.nct;
    const rawPayload = (trial.rawStudyJson || '').substring(0, 95000);

    output.push({
      json: {
        eventId,
        companyRecordId: recordId,
        companyName,
        nct: trial.nct,
        eventType: 'clinical_trial_status',
        signalStateRaw: trial.overallStatus || '',
        vitality,
        eventDate,
        mostRecentActivityDate: eventDate,
        detectedAt: runDate,
        sourceUrl: 'https://clinicaltrials.gov/study/' + trial.nct,
        provider: 'clinicaltrials.gov',
        rawReference: 'ctgov:' + trial.nct,
        detail,
        isLatest: true,
        confidence: 'high',
        briefTitle,
        studyType: trial.studyType || '',
        interventionTypes: trial.interventionTypes || '',
        interventionNames: trial.interventionNames || '',
        conditionsList: trial.conditionsList || (trial.conditions || []).join('\n'),
        meshInterventions: trial.meshInterventions || [],
        meshConditions: trial.meshConditions || [],
        primaryPurpose: trial.primaryPurpose || '',
        briefSummary: trial.briefSummary || '',
        rawStudyJson: rawPayload,
      }
    });
  }
}
return output;

// Tiered classifier: deterministic Tier 1 + Tier 3; heuristic Tier 2 (LLM augmentation deferred to v2).
// Outputs all items with classifierTier, classifierConfidence, classifierDetail added.
const items = $input.all();
const runDate = new Date().toISOString().split('T')[0];

function classifyTrial(trial) {
  const meshI = (trial.meshInterventions || []).map(m => (m.term || '').toLowerCase());
  const meshC = (trial.meshConditions || []).map(m => (m.term || '').toLowerCase());
  const allMesh = [...meshI, ...meshC];
  const intTypes = (trial.interventionTypes || '').toUpperCase().split(',').map(s => s.trim()).filter(Boolean);
  const pp = (trial.primaryPurpose || '').toUpperCase();
  const intName = (trial.interventionNames || '').toLowerCase();
  const summary = (trial.briefSummary || '').toLowerCase();

  const hasDependovirus = allMesh.some(m => m.includes('dependovirus') || m.includes('adeno-associated'));
  const hasGeneTherapyMesh = allMesh.some(m => m.includes('genetic therapy') || m.includes('gene therapy') || m.includes('gene transfer'));
  const hasGenBio = intTypes.some(t => ['GENETIC', 'BIOLOGICAL'].includes(t));
  const hasDrugDeviceOnly = intTypes.length > 0 && intTypes.every(t => ['DRUG', 'DEVICE', 'PROCEDURE'].includes(t));
  const isBasicOrDiag = ['BASIC_SCIENCE', 'DIAGNOSTIC'].includes(pp);
  const isTreatment = pp === 'TREATMENT';
  const hasAAVName = /\baav\b|adeno.associated|dependovirus/.test(intName) || /\baav\b|adeno.associated/.test(summary.substring(0, 300));

  // Tier 3: definitive reject
  if (hasDrugDeviceOnly && !hasGenBio) return { tier: 'tier3_reject', confidence: 'low', reason: 'All interventions are DRUG/DEVICE; no GENETIC/BIOLOGICAL type' };
  if (isBasicOrDiag) return { tier: 'tier3_reject', confidence: 'low', reason: `primaryPurpose=${pp}` };

  // Tier 1 high: deterministic AAV confirmation
  if (hasDependovirus && hasGenBio && isTreatment) return { tier: 'tier1_mesh_match', confidence: 'high', reason: 'MeSH Dependovirus + GENETIC/BIOLOGICAL intervention type + TREATMENT purpose' };
  if (hasDependovirus && hasGeneTherapyMesh) return { tier: 'tier1_mesh_match', confidence: 'high', reason: 'MeSH Dependovirus + gene therapy MeSH' };
  if (hasAAVName && hasGenBio && isTreatment) return { tier: 'tier1_name_match', confidence: 'high', reason: 'AAV/adeno-associated in intervention name + GENETIC/BIOLOGICAL + TREATMENT' };

  // Tier 2: ambiguous — LLM augmentation deferred; use heuristic medium
  if (hasGenBio || hasAAVName || hasDependovirus) return { tier: 'tier2_heuristic', confidence: 'medium', reason: 'Partial signals present; LLM classification pending (v2)' };

  // Tier 3 weak: no signals
  return { tier: 'tier3_weak', confidence: 'low', reason: 'No AAV signals detected in MeSH, intervention type, or intervention name' };
}

const output = [];
for (const item of items) {
  const trial = item.json;
  const cls = classifyTrial(trial);

  const meshTerms = [
    ...(trial.meshInterventions || []).map(m => m.term),
    ...(trial.meshConditions || []).map(m => m.term),
  ].filter(Boolean).join(', ');

  const evidenceDetail = [
    `Tier: ${cls.tier}`,
    `Reason: ${cls.reason}`,
    `MeSH: ${meshTerms || 'none'}`,
    `Intervention types: ${trial.interventionTypes || 'unknown'}`,
    `Primary purpose: ${trial.primaryPurpose || 'unknown'}`,
    `Study type: ${trial.studyType || 'unknown'}`,
  ].join(' | ');

  const rawPayload = JSON.stringify({
    nct: trial.nct,
    meshInterventions: trial.meshInterventions,
    meshConditions: trial.meshConditions,
    interventionTypes: trial.interventionTypes,
    interventionNames: trial.interventionNames,
    primaryPurpose: trial.primaryPurpose,
    studyType: trial.studyType,
    briefSummary: (trial.briefSummary || '').substring(0, 500),
    briefTitle: trial.briefTitle,
  }).substring(0, 95000);

  output.push({
    json: {
      ...trial,
      classifierTier: cls.tier,
      classifierConfidence: cls.confidence,
      classifierReason: cls.reason,
      classifierDetail: evidenceDetail,
      classifierRawPayload: rawPayload,
      categoriesTags: `aav-gene-therapy\n${cls.tier}`,
    }
  });
}
return output;
